/**
 * CodeParse – TTS workflow

 */

// ---------- Raw input ----------
const webhook = $items('clinicalNote')[0]?.json?.body || {};
const clinicalText = webhook.text || '';

// ---------- Patient ----------
const patientRow = $items('verifyPatient')[0]?.json || {};
const patient = patientRow.resource || {};

const patientName =
  patient.name?.[0]
    ? `${(patient.name[0].given || []).join(' ')} ${patient.name[0].family || ''}`.trim()
    : 'NA';

const patientDob = patient.birthDate || 'NA';
const patientGender = patient.gender || 'NA';

const patientMrn =
  patient.identifier?.find(i => i.system?.toLowerCase().includes('mrn'))?.value || 'NA';

// ---------- Practitioner ----------
const practitionerRow = $items('verifyPractitioner')[0]?.json || {};
const practitioner = practitionerRow.resource || {};

const practitionerName =
  practitioner.name?.[0]
    ? `${(practitioner.name[0].prefix || []).join(' ')} ${(practitioner.name[0].given || []).join(' ')} ${practitioner.name[0].family || ''}`.trim()
    : 'NA';

const practitionerEmail =
  practitioner.telecom?.find(t => t.system === 'email')?.value || 'NA';

// ---------- Encounter date ----------
const encounterDate =
  webhook.encounter_date || new Date().toISOString().split('T')[0];

// ---------- Final v17 contract ----------
return [
  {
    json: {
      clinical_text_input: clinicalText,
      encounter_date: encounterDate,

      patient_details: {
        name: patientName,
        dob: patientDob,
        gender: patientGender,
        mrn: patientMrn
      },

      provider_details: {
        name: practitionerName,
        email: practitionerEmail
      }
    }
  }
];

/**
 * CleanOutputJSON – SOAP → TTS script
 * Safe parsing + clinically constrained narration
 */

const raw = $json.text || '';
const cleaned = raw.replace(/```json|```/g, '').trim();

let note;
try {
  note = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Invalid JSON from LLM – cannot generate TTS');
}

// ---------- Safe extractors ----------
const chiefComplaint = note.chief_complaint || 'NA';
const hpi = note.subjective?.hpi_narrative || 'NA';
const assessment = note.assessment?.assessment_summary || 'NA';
const plan = note.plan?.follow_up_plan || 'NA';

// ---------- Clinically appropriate spoken summary ----------
const script = `
Clinical summary.
Chief complaint: ${chiefComplaint}.
History of present illness: ${hpi}.
Assessment: ${assessment}.
Plan: ${plan}.
`.replace(/\s+/g, ' ').trim();

return [
  {
    json: {
      script,
      voice_id: '21m00Tcm4TlvDq8ikWAM' 
    }
  }
];
